// ─── FUSION AVEC CANON ───────────────────────────────────────
// Appelé une fois au boot, avant toute initialisation de saison
function mergeGhostNations(canon) {
  if (!canon || !GHOST_NATIONS_DATA) return canon;
  if (canon._ghostMerged) return canon; // idempotent

  // Fusionne les ligues
  for (const [id, lg] of Object.entries(GHOST_NATIONS_DATA.leagues)) {
    if (!canon.leagues[id]) canon.leagues[id] = lg;
  }
  // Fusionne les clubs
  for (const [id, club] of Object.entries(GHOST_NATIONS_DATA.clubs)) {
    if (!canon.clubs[id]) canon.clubs[id] = club;
  }
  // Fusionne les joueurs
  for (const [id, player] of Object.entries(GHOST_NATIONS_DATA.players)) {
    if (!canon.players[id]) canon.players[id] = player;
  }

  canon._ghostMerged = true;
  console.log('[Ghost] Fusion terminée — ' + Object.keys(GHOST_NATIONS_DATA.clubs).length + ' clubs ajoutés');
  return canon;
}

if (typeof module !== 'undefined') module.exports = { GHOST_NATIONS_DATA, mergeGhostNations };
